from google.cloud import secretmanager
from google.oauth2 import service_account
from google.cloud import bigquery

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def buscar_credencial():
    projeto = 'comissao-prontuario'
    nome_secret = 'dbt-orquestrador-credentials'

    #abrir conexão
    cliente = secretmanager.SecretManagerServiceClient()
    
    caminho = f'projects/{projeto}/secrets/{nome_secret}/versions/latest'
    
    #buscar conteúdo no secret
    resposta = cliente.access_secret_version(name=caminho)
    
    #conversão para texto
    credencial_json = json.loads(resposta.payload.data.decode('utf-8'))
    
    #tranforma o dicionário em credencial autenticado
    credenciais = service_account.Credentials.from_service_account_info(credencial_json,
                                                                        scopes=['https://www.googleapis.com/auth/cloud-platform'])
    
    return credenciais

